from __future__ import annotations


def build_audit_trail(events, include_provenance=False):
    out = []
    for sequence, event in enumerate(events, start=1):
        source = event.get('source_system')
        actor = event.get('actor_id')
        if not source or not actor:
            raise ValueError('source_system and actor_id are required')
        row = {'sequence': sequence, 'source_system': source, 'actor_id': actor, 'action': event.get('action')}
        if include_provenance:
            row['provenance'] = f'{source}:{sequence}'
        out.append(row)
    return out
